3_real_world_example.code:
// 1. setTimeout (Runs ONCE)
const popupTimer = setTimeout(() => {
  console.log('Showing 10% discount popup!');
}, 5000); // 5000ms = 5 seconds

// We can cancel it before it happens if the user buys something!
// clearTimeout(popupTimer);

// 2. setInterval (Runs REPEATEDLY)
let seconds = 0;
const clockTimer = setInterval(() => {
  seconds++;
  console.log(`You have been on this page for ${seconds} seconds`);

  if (seconds >= 10) {
    clearInterval(clockTimer); // Stop it after 10 seconds
  }
}, 1000);

